#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

typedef struct Node {
    int fd;
    struct Node *next;
} Node;

Node* head = NULL;

void add(int fd) {
    Node* new_node = (Node*) malloc(sizeof(Node));
    new_node->fd = fd;
    new_node->next = head;
    head = new_node;
}

void remove(int fd) {
    Node *temp = head, *prev;

    if (temp != NULL && temp->fd == fd) {
        head = temp->next;
        free(temp);
        return;
    }

    while (temp != NULL && temp->fd != fd) {
        prev = temp;
        temp = temp->next;
    }

    if (temp == NULL) 
        return;
    
    prev->next = temp->next;
    free(temp);
}

void cleanup() {
    Node *current = head, *next_node;

    while (current != NULL) {
        next_node = current->next;
        close(current->fd);
        free(current);
        current = next_node;
    }
    
    head = NULL;
}